function solve(digitSum) {
    const MOD = 10**9 + 7;
    const MAX_VAL = 5000;

    /**
     * Calculates the sum of digits of a number.
     * @param {number} n
     * @returns {number}
     */
    const getDigitSum = (n) => {
        let sum = 0;
        n = Math.abs(n);
        while (n > 0) {
            sum += n % 10;
            n = Math.floor(n / 10);
        }
        return sum;
    };

    /**
     * Precomputes all numbers <= MAX_VAL that have a specific digit sum.
     * @param {number} targetSum
     * @returns {number[]} List of numbers <= MAX_VAL with digit sum = targetSum, sorted.
     */
    const precomputeNumbers = (targetSum) => {
        const validNumbers = [];
        for (let i = 0; i <= MAX_VAL; i++) {
            if (getDigitSum(i) === targetSum) {
                validNumbers.push(i);
            }
        }
        return validNumbers;
    };

    const n = digitSum.length;

    // dp[i][j] will store the number of valid sequences of length i+1 
    // such that the (i+1)-th element (arr[i]) is equal to j.
    // Since the maximum value is 5000, j goes up to 5000.
    // The constraints on digitSum[i] are small (<= 50), but the numbers themselves can be up to 5000.

    // We will use DP based on indices of digitSum and the value of the last element.
    // dp[i][last_val] = number of valid prefixes arr[0...i] such that arr[i] = last_val.

    // Since we only care about the count and the transitions depend on the *value* of the previous element, 
    // we can optimize the DP state.

    // Let's first precompute the possible numbers for each digitSum[i].
    const possibleNumbers = digitSum.map(s => precomputeNumbers(s));

    // dp[i] will be a map or an array representing the counts for index i.
    // dp[i][value] = count of valid arrays arr[0...i] where arr[i] = value.

    // Initialize dp for i = 0
    let dp = new Map(); // Map<number, number> where key is the value, value is the count.
    const num0s = possibleNumbers[0];
    for (const num of num0s) {
        dp.set(num, 1);
    }

    // Iterate from i = 1 to n-1
    for (let i = 1; i < n; i++) {
        const nextDp = new Map();
        const currentPossible = possibleNumbers[i];

        // Iterate over all possible values for the current element arr[i]
        for (const nextVal of currentPossible) {
            let count = 0;

            // Sum up counts from the previous step (dp) where the previous value <= nextVal
            for (const [prevVal, prevCount] of dp.entries()) {
                if (prevVal <= nextVal) {
                    count = (count + prevCount) % MOD;
                }
            }

            if (count > 0) {
                nextDp.set(nextVal, (nextDp.get(nextVal) || 0) + count) % MOD;
            }
        }
        dp = nextDp;
    }

    // The total count is the sum of all values in the final dp map.
    let totalCount = 0;
    for (const count of dp.values()) {
        totalCount = (totalCount + count) % MOD;
    }

    return totalCount;
}

