import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

class Solution {
    private static final int MOD = 1_000_000_007;
    private static final int MAX_VAL = 5000;

    /**
     * Calculates the sum of digits of a number.
     * @param n The number.
     * @return The sum of its digits.
     */
    private static int getDigitSum(int n) {
        int sum = 0;
        n = Math.abs(n);
        while (n > 0) {
            sum += n % 10;
            n = n / 10;
        }
        return sum;
    }

    /**
     * Precomputes all numbers <= MAX_VAL that have a specific digit sum.
     * @param targetSum The target digit sum.
     * @return List of numbers <= MAX_VAL with digit sum = targetSum, sorted.
     */
    private static List<Integer> precomputeNumbers(int targetSum) {
        List<Integer> validNumbers = new ArrayList<>();
        for (int i = 0; i <= MAX_VAL; i++) {
            if (getDigitSum(i) == targetSum) {
                validNumbers.add(i);
            }
        }
        return validNumbers;
    }

    public static long solve(long[] digitSumArray) {
        int n = (int) digitSumArray.length;
        int[] digitSum = new int[n];
        for (int i = 0; i < n; i++) {
            digitSum[i] = (int) digitSumArray[i];
        }

        // Precompute the possible numbers for each digitSum[i].
        List<List<Integer>> possibleNumbers = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            possibleNumbers.add(precomputeNumbers(digitSum[i]));
        }

        // dp[value] = count of valid prefixes arr[0...i] where arr[i] = value.
        // We use a Map for sparse storage, where key is the value and value is the count.

        // Initialize dp for i = 0
        Map<Integer, Integer> dp = new HashMap<>();
        List<Integer> num0s = possibleNumbers.get(0);
        for (int num : num0s) {
            dp.put(num, 1);
        }

        // Iterate from i = 1 to n-1
        for (int i = 1; i < n; i++) {
            Map<Integer, Integer> nextDp = new HashMap<>();
            List<Integer> currentPossible = possibleNumbers.get(i);

            // Optimization: Instead of iterating over dp entries for every nextVal, 
            // we can precompute prefix sums of counts from the previous DP state.

            // Sort the keys (previous values) in dp to enable prefix sum calculation efficiently.
            List<Integer> sortedPrevValues = new ArrayList<>(dp.keySet());
            sortedPrevValues.sort(Integer::compareTo);

            // prefixCount[k] stores the sum of counts for all prevVal <= sortedPrevValues[k]
            int maxPrevValue = sortedPrevValues.get(sortedPrevValues.size() - 1);
            int[] prefixCount = new int[sortedPrevValues.size()];
            int currentSum = 0;
            for (int k = 0; k < sortedPrevValues.size(); k++) {
                int prevVal = sortedPrevValues.get(k);
                currentSum = (currentSum + dp.get(prevVal)) % MOD;
                prefixCount[k] = currentSum;
            }

            // Iterate over all possible values for the current element arr[i]
            for (int nextVal : currentPossible) {

                // Find the sum of counts from dp where prevVal <= nextVal

                // Binary search or simple iteration to find the index of the largest prevVal <= nextVal
                int sumOfPreviousCounts = 0;

                // Since sortedPrevValues is sorted, we find the largest index k such that sortedPrevValues[k] <= nextVal
                int maxIndex = -1;
                for(int k = 0; k < sortedPrevValues.size(); k++) {
                    if (sortedPrevValues.get(k) <= nextVal) {
                        maxIndex = k;
                    } else {
                        break;
                    }
                }

                if (maxIndex >= 0) {
                    sumOfPreviousCounts = prefixCount[maxIndex];
                }

                if (sumOfPreviousCounts > 0) {
                    int currentCount = nextDp.getOrDefault(nextVal, 0);
                    int newCount = (currentCount + sumOfPreviousCounts) % MOD;
                    nextDp.put(nextVal, newCount);
                }
            }
            dp = nextDp;
        }

        // The total count is the sum of all values in the final dp map.
        long totalCount = 0;
        for (int count : dp.values()) {
            totalCount = (totalCount + count) % MOD;
        }

        return totalCount;
    }
}
