     * @param targetSum The required digit sum.
     * @return List of numbers <= MAX_VAL with digit sum = targetSum, sorted.
     */
    private static List<Integer> precomputeNumbers(int targetSum) {
        List<Integer> validNumbers = new ArrayList<>();
        for (int i = 0; i <= MAX_VAL; i++) {
            if (getDigitSum(i) == targetSum) {
                validNumbers.add(i);
            }
        }
        // The list is naturally sorted since we iterate from 0 to MAX_VAL
        return validNumbers;
    }

    public static long solve(long[] digitSumArr) {
        int n = digitSumArr.length;
        int[] digitSum = new int[n];
        for (int i = 0; i < n; i++) {
            digitSum[i] = (int) digitSumArr[i];
        }

        // Step 1: Precompute possible numbers for each target digit sum
        List<List<Integer>> possibleNumbers = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            possibleNumbers.add(precomputeNumbers(digitSum[i]));
        }

        // dp[i] will store counts for index i. We use a map: Map<Value, Count>
        // where Value is arr[i] and Count is the number of valid prefixes arr[0...i] ending in Value.

        // Initialize dp for i = 0
        Map<Integer, Long> dp = new HashMap<>();
        List<Integer> num0s = possibleNumbers.get(0);
        for (int num : num0s) {
            dp.put(num, 1L);
        }

        // Iterate from i = 1 to n-1
        for (int i = 1; i < n; i++) {
            Map<Integer, Long> nextDp = new HashMap<>();
            List<Integer> currentPossible = possibleNumbers.get(i);

            // To optimize the inner loop (finding sum of prevCount where prevVal <= nextVal), 
            // we should sort the keys of the current dp map by value (prevVal).
            List<Integer> sortedPrevVals = new ArrayList<>(dp.keySet());
            sortedPrevVals.sort(Integer::compareTo);

