import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

class Solution {
    private static final long MOD = 1_000_000_007L;
    private static final int MAX_VAL = 5000;

    /**
     * Calculates the sum of digits of a number.
     * @param n The number.
     * @return The sum of its digits.
     */
    private static int getDigitSum(int n) {
        int sum = 0;
        n = Math.abs(n);
        while (n > 0) {
            sum += n % 10;
            n /= 10;
        }
        return sum;
    }

    /**
     * Precomputes all numbers <= MAX_VAL that have a specific digit sum.
     * @param targetSum The required digit sum.
     * @return List of numbers <= MAX_VAL with digit sum = targetSum, sorted.
     */
    private static List<Integer> precomputeNumbers(int targetSum) {
        List<Integer> validNumbers = new ArrayList<>();
        for (int i = 0; i <= MAX_VAL; i++) {
            if (getDigitSum(i) == targetSum) {
                validNumbers.add(i);
            }
        }
        return validNumbers;
    }

    public static long solve(long[] digitSum) {
        int n = digitSum.length;

        // Precompute the possible numbers for each digitSum[i].
        List<List<Integer>> possibleNumbers = new ArrayList<>();
        for (long ds : digitSum) {
            // Since digitSum[i] <= 50, we can safely cast to int for precomputation
            possibleNumbers.add(precomputeNumbers((int) ds));
        }

        // dp maps: dp[value] = count of valid arrays arr[0...i] where arr[i] = value.
        // We use two maps to alternate between steps i and i+1.
        Map<Integer, Long> dp = new HashMap<>();

        // Initialize dp for i = 0
        List<Integer> num0s = possibleNumbers.get(0);
        for (int num : num0s) {
            dp.put(num, 1L);
        }

        // Iterate from i = 1 to n-1
        for (int i = 1; i < n; i++) {
            Map<Integer, Long> nextDp = new HashMap<>();
            List<Integer> currentPossible = possibleNumbers.get(i);

            // To optimize the summation: we need sum of counts for prevVal <= nextVal.
            // We can process previous values in sorted order to use a running sum, 
            // but since the number of possible values is relatively small (<= 5001), 
            // iterating over dp entries might be acceptable given the constraints.

            // Create a sorted list of previous values present in dp keys for efficient summation
            List<Integer> sortedPrevVals = new ArrayList<>(dp.keySet());
            sortedPrevVals.sort(null);

            // Precompute prefix sums of counts for previous values
            Map<Integer, Long> prefixSumCount = new HashMap<>();
            long runningSum = 0;
            for(int prevVal : sortedPrevVals) {
                runningSum = (runningSum + dp.get(prevVal)) % MOD;
                prefixSumCount.put(prevVal, runningSum);
            }


            // Iterate over all possible values for the current element arr[i]
            for (int nextVal : currentPossible) {
                long count = 0;

                // Find the sum of dp[prevVal] where prevVal <= nextVal.
                // We find the largest prevVal <= nextVal in sortedPrevVals.
                int upper_bound_index = -1;
                for(int j = sortedPrevVals.size() - 1; j >= 0; j--) {
                    if (sortedPrevVals.get(j) <= nextVal) {
                        upper_bound_index = j;
                        break;
                    }
                }

                if (upper_bound_index != -1) {
                    // The running sum up to this value is the required sum.
                    int largestRelevantPrevVal = sortedPrevVals.get(upper_bound_index);
                    count = prefixSumCount.get(largestRelevantPrevVal);
                }

                if (count > 0) {
                    nextDp.put(nextVal, (nextDp.getOrDefault(nextVal, 0L) + count) % MOD);
                }
            }
            dp = nextDp;
        }

        // The total count is the sum of all values in the final dp map.
        long totalCount = 0;
        for (long count : dp.values()) {
            totalCount = (totalCount + count) % MOD;
        }

        return totalCount;
    }
